import { useState } from "react";
import { useAccount, useChainId, useSwitchChain, useWalletClient } from "wagmi";
import {
  createOrderlyKey,
  type CreateOrderlyKeyResult,
} from "@/utils/orderlyKey";
import { getProfile } from "@/utils/branding-shared";
import { resolveWalletAccount } from "@/services/orderly";
import { walletGetItem } from "@/utils/storage";

export interface CreateKeyParams {
  brokerId: string;
  delegateContract?: string;
  rememberSigningKey?: boolean;
}

export interface UseCreateOrderlyKeyResult {
  create: (params: CreateKeyParams) => Promise<CreateOrderlyKeyResult>;
  loading: boolean;
  switching: boolean;
  error: string;
  clearError: () => void;
}

async function resolveMultisigChainId(
  address: string
): Promise<number | undefined> {
  try {
    const token = walletGetItem("auth_token") || undefined;
    const resolution = await resolveWalletAccount(address, token, {
      skipAmbassadorCheck: true,
    });
    if (resolution.kind === "builder" && resolution.multisigChainId) {
      return Number(resolution.multisigChainId);
    }
  } catch {
    // fall back to the locally stored (backend-sourced) value below
  }
  const profile = getProfile();
  return profile?.multisigChainId ? Number(profile.multisigChainId) : undefined;
}

export function useCreateOrderlyKey(): UseCreateOrderlyKeyResult {
  const { address } = useAccount();
  const connectedChainId = useChainId();
  const { data: walletClient } = useWalletClient();
  const { switchChainAsync } = useSwitchChain();
  const [loading, setLoading] = useState(false);
  const [switching, setSwitching] = useState(false);
  const [error, setError] = useState("");

  async function create(
    params: CreateKeyParams
  ): Promise<CreateOrderlyKeyResult> {
    const { brokerId, delegateContract, rememberSigningKey } = params;
    setError("");
    if (!address || !walletClient) {
      const msg = "Connect a wallet before creating an Orderly API key.";
      setError(msg);
      throw new Error(msg);
    }
    if (!brokerId) {
      const msg = "No broker ID available. Create a builder profile first.";
      setError(msg);
      throw new Error(msg);
    }

    let chainId = Number(connectedChainId || 1);

    if (delegateContract && address) {
      setSwitching(true);
      try {
        const multisigChainId = await resolveMultisigChainId(address);
        if (multisigChainId) {
          chainId = multisigChainId;
        }
        if (chainId !== connectedChainId) {
          try {
            await switchChainAsync({ chainId });
          } catch {
            const msg = `Switch your wallet to chain ${chainId} to sign for the multisig account, then try again.`;
            setError(msg);
            throw new Error(msg);
          }
        }
      } finally {
        setSwitching(false);
      }
    }

    setLoading(true);
    try {
      return await createOrderlyKey({
        walletClient,
        address,
        chainId,
        brokerId,
        scope: "read",
        delegateContract,
        rememberSigningKey,
      });
    } catch (e) {
      const msg =
        e instanceof Error ? e.message : "Failed to create Orderly API key.";
      setError(msg);
      throw e;
    } finally {
      setLoading(false);
    }
  }

  return {
    create,
    loading,
    switching,
    error,
    clearError: () => setError(""),
  };
}
