import { getPublicKeyAsync, utils } from "@noble/ed25519";
import {
  AbiCoder,
  encodeBase58,
  keccak256,
  solidityPackedKeccak256,
} from "ethers";
import type { WalletClient } from "viem";
import { walletClientToEthersSigner } from "./ethersWallet";
import { getOffChainDomain } from "./eip712";
import { getOrderlyEnvConfig } from "./environment";
import { apiClient } from "./api";
import { walletSetItem } from "./storage";
import { saveDexCreatorStyleOrderlyKey } from "./adminKeyAuth";

type Scope = "read" | "read,trading";

const ADD_KEY_TYPES = {
  AddOrderlyKey: [
    { name: "brokerId", type: "string" },
    { name: "chainId", type: "uint256" },
    { name: "orderlyKey", type: "string" },
    { name: "scope", type: "string" },
    { name: "timestamp", type: "uint64" },
    { name: "expiration", type: "uint64" },
  ],
};

const DELEGATE_ADD_KEY_TYPES = {
  DelegateAddOrderlyKey: [
    { name: "delegateContract", type: "address" },
    { name: "brokerId", type: "string" },
    { name: "chainId", type: "uint256" },
    { name: "orderlyKey", type: "string" },
    { name: "scope", type: "string" },
    { name: "timestamp", type: "uint64" },
    { name: "expiration", type: "uint64" },
  ],
};

function getAccountId(address: string, brokerId: string): string {
  return keccak256(
    AbiCoder.defaultAbiCoder().encode(
      ["address", "bytes32"],
      [address, solidityPackedKeccak256(["string"], [brokerId])]
    )
  );
}

export interface CreateOrderlyKeyResult {
  accountId: string;
  orderlyKey: string;
  secret: string;
  publicKey: string;
  expiresAt: string;
}

export interface CreateOrderlyKeyParams {
  walletClient: WalletClient;
  address: string;
  chainId: number;
  brokerId: string;
  scope?: Scope;
  delegateContract?: string;
  rememberSigningKey?: boolean;
}

export async function createOrderlyKey(
  params: CreateOrderlyKeyParams
): Promise<CreateOrderlyKeyResult> {
  const {
    walletClient,
    address,
    chainId,
    brokerId,
    scope = "read",
    delegateContract,
    rememberSigningKey,
  } = params;
  const envConfig = getOrderlyEnvConfig();
  const signer = await walletClientToEthersSigner(walletClient);

  const privateKey = utils.randomPrivateKey();
  const publicKey = await getPublicKeyAsync(privateKey);
  const orderlyKey = `ed25519:${encodeBase58(publicKey)}`;
  const timestamp = Date.now();
  const expiresAt = timestamp + 1_000 * 60 * 60 * 24 * 365;

  const effectiveAddress = delegateContract || address;
  const accountId = getAccountId(effectiveAddress, brokerId);

  if (delegateContract) {
    const message = {
      delegateContract,
      brokerId,
      chainId: Number(chainId),
      orderlyKey,
      scope,
      timestamp,
      expiration: expiresAt,
    };
    const signature = await signer.signTypedData(
      getOffChainDomain(chainId),
      DELEGATE_ADD_KEY_TYPES,
      message
    );
    const data = await apiClient<{ success?: boolean; message?: string }>({
      endpoint: "/v1/delegate_orderly_key",
      method: "POST",
      token: null,
      body: { message, signature, userAddress: address },
      showToastOnError: false,
    });
    if (data.success === false) {
      throw new Error(
        data.message || "Failed to create delegate Orderly API key."
      );
    }
  } else {
    const message = {
      brokerId,
      chainId: Number(chainId),
      orderlyKey,
      scope,
      timestamp,
      expiration: expiresAt,
    };
    const signature = await signer.signTypedData(
      getOffChainDomain(chainId),
      ADD_KEY_TYPES,
      message
    );
    const data = await apiClient<{ success?: boolean; message?: string }>({
      endpoint: "/v1/orderly_key",
      method: "POST",
      token: null,
      body: { message, signature, userAddress: address },
      showToastOnError: false,
    });
    if (data.success === false) {
      throw new Error(data.message || "Failed to create Orderly API key.");
    }
  }

  const secret = encodeBase58(privateKey);
  const publicKeyBase58 = orderlyKey.replace(/^ed25519:/i, "");

  saveDexCreatorStyleOrderlyKey(accountId, secret);
  walletSetItem(
    "orderlyApiKey",
    JSON.stringify({
      accountId,
      key: publicKeyBase58,
      token: publicKeyBase58,
      secret,
      brokerId,
      env: envConfig.env,
      dexCreatorEnv: envConfig.dexCreatorEnv,
      ownerWalletAddress: address,
      rememberSigningKey,
      expiresAt: new Date(expiresAt).toISOString(),
    })
  );
  window.dispatchEvent(new CustomEvent("authChanged"));

  return {
    accountId,
    orderlyKey,
    secret,
    publicKey: publicKeyBase58,
    expiresAt: new Date(expiresAt).toISOString(),
  };
}
