import React from "react";
import { X } from "lucide-react";

interface ModalProps {
  open: boolean;
  onClose: () => void;
  children: React.ReactNode;
  showCloseButton?: boolean;
  title?: string;
  className?: string;
}

export function Modal({
  open,
  onClose,
  children,
  showCloseButton = true,
  title,
  className,
}: ModalProps) {
  if (!open) return null;

  return (
    <div
      className="fixed inset-0 z-[100] flex items-center justify-center bg-[var(--bg-overlay)] p-4 animate-slide-up"
      onClick={e => {
        if (e.target === e.currentTarget) onClose();
      }}
    >
      <div
        className={`relative flex max-h-[90vh] w-full flex-col overflow-hidden rounded-2xl border border-[var(--border-subtle)] bg-[var(--bg-surface-primary)] shadow-[var(--shadow-popout)] animate-slide-up ${className || "max-w-[540px]"}`}
      >
        {title ? (
          <div className="flex items-center justify-between border-b border-[var(--border-subtle)] p-5">
            <h2 className="text-lg font-medium text-[var(--fg-base)]">
              {title}
            </h2>
            {showCloseButton && (
              <button
                type="button"
                onClick={onClose}
                aria-label="Close"
                className="cursor-pointer text-[var(--fg-secondary)] transition-colors hover:text-[var(--fg-base)]"
              >
                <X size={20} />
              </button>
            )}
          </div>
        ) : (
          showCloseButton && (
            <button
              type="button"
              onClick={onClose}
              aria-label="Close"
              className="absolute right-4 top-4 z-10 flex h-8 w-8 items-center justify-center rounded-lg text-[var(--fg-secondary)] transition-colors hover:bg-[var(--bg-hover)] hover:text-[var(--fg-base)]"
            >
              <X size={20} />
            </button>
          )
        )}
        <div className={`overflow-y-auto ${title ? "p-5" : "p-8"}`}>
          {children}
        </div>
      </div>
    </div>
  );
}
